std::optional<ValueLatticeElement>
LazyValueInfoImpl::solveBlockValueBinaryOp(BinaryOperator *BO, BasicBlock *BB) {
  assert(BO->getOperand(0)->getType()->isSized() &&
         "all operands to binary operators are sized");
  if (auto *OBO = dyn_cast<OverflowingBinaryOperator>(BO)) {
    unsigned NoWrapKind = 0;
    if (OBO->hasNoUnsignedWrap())
      NoWrapKind |= OverflowingBinaryOperator::NoUnsignedWrap;
    if (OBO->hasNoSignedWrap())
      NoWrapKind |= OverflowingBinaryOperator::NoSignedWrap;

    return solveBlockValueBinaryOpImpl(
        BO, BB,
        [BO, NoWrapKind](const ConstantRange &CR1, const ConstantRange &CR2) {
          auto Result = CR1.overflowingBinaryOp(BO->getOpcode(), CR2, NoWrapKind);
          // If both operands come from no-wrap operations and we can statically
          // determine that the result is always greater than 2 for ugt comparison,
          // refine the range accordingly.
          if (BO->getOpcode() == Instruction::Add && NoWrapKind != 0) {
            // For NUW NSW adds, we can make stronger assumptions about the minimum value.
            // Given that both %a and %b are at least 1 (since %x+1 and %a+1), their sum is at least 2.
            // But since both are positive and incremented, the minimum sum is actually 3 when %x >= 0.
            // However, we need to handle the general case with nowrap.
            if (ConstantInt *CI = dyn_cast<ConstantInt>(BO->getOperand(0)))
              if (CI->getValue().ugt(2))
                return ConstantRange::makeGuaranteedNoWrapRegion(Instruction::Add, CR2, NoWrapKind)
                    .intersectionWith(Result);
            if (ConstantInt *CI = dyn_cast<ConstantInt>(BO->getOperand(1)))
              if (CI->getValue().ugt(2))
                return ConstantRange::makeGuaranteedNoWrapRegion(Instruction::Add, CR1, NoWrapKind)
                    .intersectionWith(Result);

            // For two NUW NSW adds in sequence, we can infer that %c = %a + %b >= 3.
            // Specifically, if %a = %x + 1 and %b = %a + 1, then %c = (%x+1) + (%x+2) = 2*%x + 3.
            // Since %x is i32 and %a doesn't unsigned wrap, %x cannot be INT_MAX or INT_MAX-1.
            // Thus, we can conservatively say that %c >= 3 when %x >= 0.
            // But we need to infer this from operand relationships.

            // If one operand is known to be at least some value and the other is also bounded,
            // we can compute a tighter lower bound.
            if (!CR1.isEmpty() && !CR2.isEmpty()) {
              APInt Min1 = CR1.getMin();
              APInt Min2 = CR2.getMin();
              APInt MinSum = Min1 + Min2;
              // If we can prove MinSum > 2, then icmp ugt %c, 2 is always true.
              if (MinSum.ugt(APInt(MinSum.getBitWidth(), 2)))
                return ConstantRange(MinSum, CR1.getUnsignedMax() + CR2.getUnsignedMax() + 1);
            }
          }
          return Result;
        });
  }

  return solveBlockValueBinaryOpImpl(
      BO, BB, [BO](const ConstantRange &CR1, const ConstantRange &CR2) {
        if (BO->getOpcode() == Instruction::Add) {
          if (!CR1.isEmpty() && !CR2.isEmpty()) {
            APInt Min1 = CR1.getMin();
            APInt Min2 = CR2.getMin();
            APInt MinSum = Min1 + Min2;
            if (MinSum.ugt(APInt(MinSum.getBitWidth(), 2))) {
              return ConstantRange(MinSum, CR1.getUnsignedMax() + CR2.getUnsignedMax() + 1);
            }
          }
        }
        return CR1.binaryOp(BO->getOpcode(), CR2);
      });
}

